13	  // We'll just strip leading zeros to normalize
14	  const normalizeSupplierId = (id: string) => id.replace(/^0+/, '');
15	
16	  // 1. Extract unique suppliers
17	  const supplierMap = new Map<string, { id: string; name: string }>();
18	  for (const item of cartData.products) {
19	    const rawId = item.supplier.supplierId;
20	    const normId = normalizeSupplierId(rawId);
21	    if (!supplierMap.has(normId)) {
22	      supplierMap.set(normId, { id: normId, name: item.supplier.supplierName });
23	    }
24	  }
25	
26	  // Insert suppliers
27	  for (const supplier of supplierMap.values()) {
28	    // Upsert or insert if not exists (we just insert since DB is in-memory and fresh)
29	    db.insert(suppliers).values(supplier).execute();
30	  }
31	
32	  // 2. Insert products and cart items
